1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	function premiumForItem(item: { type: string }): number {
12	  return BASE_PREMIUMS[item.type] + FIRST_INSURANCE_SURCHARGE;
13	}
14	
15	export function quote(input: { items: { type: string }[]; years: number; priorContract: boolean }): { premium: number } {
16	  const itemsTotal = input.items.reduce((sum, item) => sum + premiumForItem(item), 0);
17	  return { premium: itemsTotal + PROCESSING_FEE };
18	}
19	
